namespace QBEngineer.Api.Data.TrainingContent;

public class MfaTraining : TrainingContentBase
{
    public MfaTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Multi-Factor Authentication Overview",
            Slug = "mfa-overview",
            Summary = "What MFA is, how TOTP authenticator apps work, recovery codes, and admin-enforced policies.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/account/security"]""",
            Tags = """["mfa","security"]""",
            ContentJson = """{"body":"## Multi-Factor Authentication (MFA)\n\nMulti-factor authentication adds an extra layer of security to your QB Engineer account. Instead of relying on your password alone, MFA requires a second verification step — a time-based code from an authenticator app — every time you sign in.\n\n### What Is TOTP?\n\nTOTP stands for Time-based One-Time Password. When you enable MFA, QB Engineer generates a secret key that you register with an authenticator app on your phone. The app uses this key plus the current time to produce a 6-digit code that changes every 30 seconds. When you sign in, you enter your password first, then the current code from your app. Because the code changes constantly and requires your physical device, a stolen password alone is not enough to access your account.\n\n### Supported Authenticator Apps\n\nAny TOTP-compatible authenticator app works with QB Engineer:\n- **Google Authenticator** — simple, widely used\n- **Authy** — supports cloud backup and multi-device sync\n- **Microsoft Authenticator** — integrates with Microsoft accounts\n- **1Password / Bitwarden** — password managers with built-in TOTP support\n\nDuring setup, you scan a QR code with your chosen app, or manually enter the secret key if scanning is not possible.\n\n### Recovery Codes\n\nRecovery codes are one-time-use backup codes that let you sign in if you lose access to your authenticator app (lost phone, factory reset, app deleted). QB Engineer generates a set of codes when you enable MFA, and you can regenerate them at any time from Account > Security.\n\n**Important rules about recovery codes:**\n- Each code can only be used once — after use it is permanently consumed\n- Generating new codes invalidates all previous codes\n- Store them somewhere safe and separate from your phone (printed, in a password manager, or in a secure document)\n- The Security page shows how many unused codes you have remaining\n\n### The Login Flow with MFA\n\n1. Enter your email and password as usual\n2. If MFA is enabled, you see a challenge screen asking for your 6-digit code\n3. Open your authenticator app and enter the current code\n4. Optionally check \"Remember this device\" to skip MFA on trusted devices\n5. If you cannot access your authenticator, click \"Use recovery code\" and enter one of your backup codes\n\n### Admin-Enforced MFA Policies\n\nAdministrators can require MFA for specific roles (e.g., Admin, Manager). When a policy is enforced:\n- Users in the affected roles see a warning on their Security page: \"Required by organization policy\"\n- The Disable MFA button is hidden — you cannot turn off MFA while the policy applies to your role\n- New users assigned to an enforced role must set up MFA on their next login\n- The Admin > MFA panel shows a compliance table listing all users, their MFA status, device type, and whether their role is enforced\n\n### When to Use MFA\n\n- **Always recommended** for all users to protect against password breaches\n- **Required** when your admin has enforced an MFA policy for your role\n- **Especially important** for Admin and Manager roles that have access to sensitive data, user management, and system settings\n- **Critical** if you access QB Engineer from shared or public computers","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MFA Setup — Guided Tour",
            Slug = "mfa-walkthrough",
            Summary = "A guided tour of Account > Security MFA section: enabling MFA, scanning QR codes, verifying codes, managing devices, and recovery codes.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/account/security"]""",
            Tags = """["mfa","security","walkthrough"]""",
            ContentJson = """{"appRoute":"/account/security","startButtonLabel":"Tour MFA Setup","steps":[{"element":".security__mfa-status","popover":{"title":"MFA Status Banner","description":"This banner shows whether two-factor authentication is currently enabled or disabled on your account. A green shield with 'enabled' means MFA is active. A gray shield with 'not enabled' means your account relies on password only.","side":"bottom"}},{"element":".account-page__actions .action-btn--primary","popover":{"title":"Enable / Add Device Button","description":"Click 'Enable Two-Factor Authentication' to start the setup wizard. If MFA is already enabled, this becomes 'Add Device' to register an additional authenticator app. The setup dialog guides you through QR scanning and code verification.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MFA Field Reference",
            Slug = "mfa-field-reference",
            Summary = "Complete reference for MFA setup fields, QR code, manual key, recovery codes, admin policy controls, login challenge, and validation rules.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/account/security"]""",
            Tags = """["mfa","security","reference"]""",
            ContentJson = """{"title":"MFA Field Reference","groups":[{"heading":"MFA Status (Account > Security)","items":[{"label":"Status Banner","value":"Shows 'Two-factor authentication is enabled' (green verified_user icon) or 'Two-factor authentication is not enabled' (gray shield icon). Reflects the current state of MFA on your account."},{"label":"Policy Enforcement Badge","value":"Displayed when an admin has required MFA for your role. Shows 'Required by organization policy' with a policy icon. When enforced and MFA is disabled, shows a warning icon with 'Required by organization policy — you must enable MFA'."},{"label":"Recovery Codes Remaining","value":"Displays the count of unused recovery codes (e.g., '8 recovery codes remaining'). Shows a vpn_key icon. Zero remaining means you have no backup if you lose your authenticator."}]},{"heading":"MFA Setup Dialog Fields","items":[{"label":"QR Code","value":"A 200x200 pixel QR code encoding the TOTP secret URI. Scan with any TOTP-compatible authenticator app (Google Authenticator, Authy, Microsoft Authenticator, 1Password, Bitwarden). Error correction level: M."},{"label":"Manual Entry Key","value":"Hidden by default behind a 'Can't scan? Enter key manually' toggle. Displays the TOTP secret as a text string in monospace font. Includes a copy-to-clipboard button. Use when QR scanning is not available."},{"label":"Verification Code (required)","value":"Text input, 6 characters max. Enter the current 6-digit code displayed in your authenticator app. Must match the expected TOTP value. data-testid: mfa-verify-code"},{"label":"Verify & Enable Button","value":"Submits the verification code. Disabled when the code field is empty or invalid, or while verification is in progress. On success, MFA is immediately enabled. On failure, an error message appears below the input. data-testid: mfa-verify-submit"}]},{"heading":"MFA Setup Dialog Steps","items":[{"label":"Step 1: Loading","value":"Shows a spinner with 'Preparing authenticator setup...' while the server generates the TOTP secret and QR code URI."},{"label":"Step 2: Scan & Verify","value":"Displays the QR code, manual key toggle, and verification code input. User scans QR, then enters the code from their authenticator app."},{"label":"Step 3: Complete","value":"Success screen with verified_user icon and confirmation message. Reminds user to generate recovery codes from the Security page."}]},{"heading":"Registered Devices Section","items":[{"label":"Device Name","value":"The name of the registered device (e.g., 'My Phone', 'Work Tablet'). Falls back to the device type (e.g., 'Totp') if no name was provided."},{"label":"Device Type Icon","value":"phone_android for TOTP devices, key for WebAuthn/hardware keys."},{"label":"Last Used Date","value":"Date the device was last used for authentication, formatted as MM/dd/yyyy. Blank if never used."},{"label":"Default Badge","value":"Blue 'Default' chip shown on the primary MFA device. The default device is used first during login challenges."},{"label":"Remove Device Button","value":"Red trash icon button. Opens a confirmation dialog warning that removing your only device may lock you out. Requires confirmation before deletion."}]},{"heading":"Recovery Codes Dialog","items":[{"label":"Warning Message","value":"Server-provided warning text explaining that generating new codes invalidates all previous codes. Displayed with a yellow warning icon."},{"label":"Code Grid","value":"Displays all generated recovery codes in a grid of monospace code blocks. Each code is a one-time-use backup for signing in without your authenticator."},{"label":"Copy All Button","value":"Copies all recovery codes to the clipboard as a newline-separated list."},{"label":"Download Button","value":"Downloads all recovery codes as a text file for offline storage."},{"label":"I've Saved These Codes Button","value":"Primary action button that closes the dialog. Confirms the user has saved their codes somewhere safe."}]},{"heading":"Admin MFA Policy Panel (Admin > MFA)","items":[{"label":"Required for Roles (multi-select)","value":"Multi-select dropdown listing all system roles (e.g., Admin, Manager, Engineer, PM, Production Worker, Office Manager). Selected roles have MFA enforced — users in those roles cannot disable MFA and must set it up if not already enabled."},{"label":"Save Button","value":"Saves the selected role enforcement policy. data-testid: mfa-save-policy"},{"label":"User Compliance Table","value":"DataTable showing all users with columns: Name (sortable), Email (sortable), Role (sortable, filterable), MFA Enabled (sortable — green 'Enabled' or gray 'Disabled' chip), Device Type (sortable — shows device type or dash), Enforced (sortable — yellow 'Enforced' chip or dash). tableId: mfa-compliance"}]},{"heading":"Login MFA Challenge","items":[{"label":"Challenge Screen","value":"Appears after successful password authentication when MFA is enabled. Shows a prompt to enter the 6-digit code from your authenticator app."},{"label":"Challenge Token","value":"Server-issued temporary token that identifies the authentication session. Passed back with the verification code. Not visible to the user."},{"label":"Verification Code Input","value":"6-digit numeric input. Must match the current TOTP code for the user's registered device."},{"label":"Remember This Device","value":"Checkbox option to skip MFA on this device for future logins. Sets a trusted device cookie."},{"label":"Use Recovery Code","value":"Link/button to switch to recovery code entry mode instead of TOTP code. Enter one of your one-time backup codes."},{"label":"Masked Target","value":"For SMS/Email MFA types, shows a masked phone number or email (e.g., '***-***-1234' or 'j***@example.com'). Not applicable for TOTP."}]},{"heading":"Validation Rules","items":[{"label":"Verification Code","value":"Required. Must be exactly 6 digits. Must match the current TOTP value for the registered secret. Invalid codes show an inline error below the input field."},{"label":"Recovery Code","value":"Required. Must match one of the user's unused recovery codes. Used codes are permanently consumed and cannot be reused."},{"label":"MFA Device Removal","value":"Requires confirmation dialog (severity: danger). Warning message notes that removing the only device may cause lockout."},{"label":"MFA Disable","value":"Requires confirmation dialog (severity: danger). Removes all devices and recovery codes. Cannot be performed when MFA is enforced by admin policy."},{"label":"Admin Policy Save","value":"At least zero roles can be selected (empty selection means no enforcement). Changes take effect immediately on save."}]},{"heading":"MFA Device Types","items":[{"label":"Totp","value":"Time-based One-Time Password. Primary and recommended method. Uses authenticator apps (Google Authenticator, Authy, etc.) to generate 6-digit codes that rotate every 30 seconds."},{"label":"WebAuthn","value":"Hardware security keys (YubiKey, etc.) or platform authenticators (Windows Hello, Touch ID). Uses public-key cryptography — stores CredentialId, PublicKey, and SignCount."},{"label":"Sms","value":"Verification code sent via SMS to a registered phone number. Less secure than TOTP due to SIM swapping risks."},{"label":"Email","value":"Verification code sent to a registered email address. Fallback option when other methods are unavailable."}]},{"heading":"Entity Fields (UserMfaDevice)","items":[{"label":"DeviceType","value":"Enum: Totp, Sms, Email, WebAuthn. Determines the authentication method and which fields are relevant."},{"label":"EncryptedSecret","value":"The TOTP secret key, encrypted at rest via ASP.NET Data Protection API. Used to generate/validate TOTP codes. Never exposed to the client after setup."},{"label":"DeviceName","value":"Optional user-provided name for the device (e.g., 'My iPhone'). Displayed in the device list. Falls back to DeviceType if null."},{"label":"IsVerified","value":"Boolean. True after the user successfully verifies a code during setup. Unverified devices are not usable for login."},{"label":"IsDefault","value":"Boolean. The primary device used first during login challenges. Only one device per user should be default."},{"label":"LastUsedAt","value":"Timestamp of the last successful authentication with this device. Null if never used. Displayed as MM/dd/yyyy in the UI."},{"label":"FailedAttempts","value":"Counter for consecutive failed verification attempts. Used for lockout logic."},{"label":"LockedUntil","value":"Timestamp until which the device is locked due to too many failed attempts. Null when not locked."}]},{"heading":"Entity Fields (MfaRecoveryCode)","items":[{"label":"CodeHash","value":"PBKDF2 hash of the recovery code. The plaintext code is only shown once during generation and never stored."},{"label":"IsUsed","value":"Boolean. Set to true when the code is consumed during a recovery login. Used codes cannot be reused."},{"label":"UsedAt","value":"Timestamp when the code was consumed. Null if not yet used."},{"label":"UsedFromIp","value":"IP address from which the recovery code was used. Recorded for security audit purposes."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MFA Knowledge Check",
            Slug = "mfa-quiz",
            Summary = "Test your knowledge of multi-factor authentication: TOTP setup, recovery codes, admin policies, and login flow.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/account/security"]""",
            Tags = """["mfa","security","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"mfa1","text":"You want to enable two-factor authentication on your QB Engineer account. Where do you go?","options":[{"id":"a","text":"Admin > Users > edit your profile and toggle MFA on"},{"id":"b","text":"Account > Security, then click 'Enable Two-Factor Authentication' in the MFA card","isCorrect":true},{"id":"c","text":"Settings > Privacy > Two-Factor tab"},{"id":"d","text":"Login screen > click 'Set up MFA' link"}],"explanation":"MFA is set up from Account > Security. The Two-Factor Authentication card shows your current status and provides the Enable button, which opens the setup dialog with QR code and verification."},{"id":"mfa2","text":"During MFA setup, the QR code cannot be scanned by your authenticator app. What should you do?","options":[{"id":"a","text":"Contact your admin to manually enable MFA on your account"},{"id":"b","text":"Click 'Can't scan? Enter key manually' to reveal the secret key, then type it into your authenticator app","isCorrect":true},{"id":"c","text":"Use a different browser and try again"},{"id":"d","text":"Skip MFA setup — it will work without scanning"}],"explanation":"The setup dialog has a toggle labeled 'Can't scan? Enter key manually' that reveals the TOTP secret as a copyable text string. You can paste this key into your authenticator app's manual entry option."},{"id":"mfa3","text":"You've entered a 6-digit code from your authenticator app but the verification failed. Why might this happen?","options":[{"id":"a","text":"Your authenticator app is not compatible with QB Engineer"},{"id":"b","text":"The code has already rotated — TOTP codes change every 30 seconds, so the code you entered may have expired","isCorrect":true},{"id":"c","text":"MFA only works with Google Authenticator, not other apps"},{"id":"d","text":"You need to scan the QR code again before entering a code"}],"explanation":"TOTP codes rotate every 30 seconds. If you entered a code just as it was expiring, it may fail validation. Wait for the next code to appear in your authenticator app and try again."},{"id":"mfa4","text":"You've lost your phone and can't access your authenticator app. How do you sign in to QB Engineer?","options":[{"id":"a","text":"You cannot — contact your admin to reset your account"},{"id":"b","text":"On the MFA challenge screen, click 'Use recovery code' and enter one of your saved backup codes","isCorrect":true},{"id":"c","text":"Use your kiosk PIN instead of the MFA code"},{"id":"d","text":"Wait 24 hours and MFA automatically disables itself"}],"explanation":"Recovery codes are one-time-use backup codes generated when you set up MFA. On the login MFA challenge screen, switch to recovery code entry mode and use one of your saved codes. Each code can only be used once."},{"id":"mfa5","text":"You just generated new recovery codes. What happens to your old recovery codes?","options":[{"id":"a","text":"They remain valid alongside the new ones for 30 days"},{"id":"b","text":"All previous recovery codes are immediately invalidated — only the new set works","isCorrect":true},{"id":"c","text":"Old codes continue working but are marked as deprecated"},{"id":"d","text":"Nothing — you can have multiple sets of active recovery codes"}],"explanation":"Generating new recovery codes invalidates all previous codes immediately. This is a security measure to ensure only one set of valid codes exists at any time. The dialog warns you about this before generating."},{"id":"mfa6","text":"Your admin has enforced MFA for your role. What changes on your Security page?","options":[{"id":"a","text":"Nothing changes — enforcement only affects new users"},{"id":"b","text":"A policy badge appears saying 'Required by organization policy' and the Disable MFA button is hidden","isCorrect":true},{"id":"c","text":"Your MFA is automatically enabled without any setup needed"},{"id":"d","text":"You receive a one-time email with instructions but can still disable MFA"}],"explanation":"When MFA is enforced by admin policy, your Security page shows a 'Required by organization policy' badge and the Disable MFA button is hidden. You cannot turn off MFA while the policy applies to your role. If MFA is not yet enabled, a warning urges you to set it up."},{"id":"mfa7","text":"As an admin, you want to require MFA for all Manager and Admin users. How do you do this?","options":[{"id":"a","text":"Edit each user individually and check 'Require MFA' on their profile"},{"id":"b","text":"Go to Admin > MFA, select Manager and Admin in the 'Required for Roles' multi-select, and click Save","isCorrect":true},{"id":"c","text":"Enable a global setting that forces MFA for all users regardless of role"},{"id":"d","text":"Send an email notification asking those users to enable MFA voluntarily"}],"explanation":"The Admin > MFA panel has a 'Required for Roles' multi-select dropdown. Select the roles you want to enforce (e.g., Manager, Admin) and click Save. The compliance table below shows which users have MFA enabled and which roles are enforced."},{"id":"mfa8","text":"In the Admin MFA compliance table, a user shows 'Disabled' under MFA Enabled and 'Enforced' under the Enforced column. What does this mean?","options":[{"id":"a","text":"The user has disabled MFA against policy — no action needed"},{"id":"b","text":"The user's role requires MFA but they haven't set it up yet — they'll be prompted on next login","isCorrect":true},{"id":"c","text":"There's a system error — enforcement and disabled status can't coexist"},{"id":"d","text":"The user was recently removed from an enforced role"}],"explanation":"When a user's role has MFA enforced but they haven't set it up yet, the compliance table shows Disabled + Enforced. The user will see a warning on their Security page and must complete MFA setup. They cannot bypass this requirement."},{"id":"mfa9","text":"You have two authenticator devices registered. One shows a blue 'Default' chip. What does the Default designation mean?","options":[{"id":"a","text":"It's the only device that can be used — the other is a backup that must be activated first"},{"id":"b","text":"It's the device used first during login challenges — the system prompts for a code from this device before trying others","isCorrect":true},{"id":"c","text":"It's the device that was registered first chronologically"},{"id":"d","text":"It receives push notifications while the non-default device requires manual code entry"}],"explanation":"The Default device is the one used first during the login MFA challenge. When you sign in, the system prompts for a code from your default device. You can still use any registered device, but the default is the primary one presented."},{"id":"mfa10","text":"You want to remove an MFA device from your account, but it's your only registered device. What happens?","options":[{"id":"a","text":"The system prevents removal — you must have at least one device"},{"id":"b","text":"A confirmation dialog warns that removing your only device may lock you out, and you must confirm the deletion","isCorrect":true},{"id":"c","text":"The device is removed and MFA is automatically disabled"},{"id":"d","text":"The device is removed but a temporary bypass code is emailed to you"}],"explanation":"Clicking the delete icon on your only device opens a danger-severity confirmation dialog warning that you may lose access to your account. If you confirm, the device is removed. You should have recovery codes saved as a backup, or disable MFA entirely if you no longer want it."}]}"""
        });

        Log.Information("Seeded MFA training modules");
    }
}
